-- ==========================================================
-- accounts seed — Стандарт IFRS загвар дансны төлөвлөгөө (хоёр хэлтэй)
-- Нийт: 138 данс. Код: 1 хөрөнгө · 3 өр · 5 өмч · 6 орлого · 7-8 зардал.
-- Хүснэгт хоосон үед л оруулна. Supabase SQL Editor-д ажиллуулна.
-- ==========================================================

DO $$
BEGIN
IF (SELECT COUNT(*) FROM accounts) = 0 THEN


PERFORM setval(pg_get_serial_sequence('accounts','id'),
               (SELECT MAX(id) FROM accounts));

END IF;
END $$;
